describe('resolveRegistry', () => {
  it('resolves GitHub shorthand to github', () => {
    expect(resolveRegistry('vercel-labs/skills')).toBe('github');
  });

  it('resolves GitHub full URL to github', () => {
    expect(resolveRegistry('https://github.com/mattpocock/skills')).toBe(
      'github'
    );
  });

  it('resolves github: prefix to github', () => {
    expect(resolveRegistry('github:owner/repo')).toBe('github');
  });

  it('resolves gitlab URL containing "gitlab" to gitlab', () => {
    expect(
      resolveRegistry('https://gitlab.example.com/group/repo.git')
    ).toBe('gitlab');
  });

  it('resolves gitlab: prefix to gitlab', () => {
    expect(resolveRegistry('gitlab:group/repo')).toBe('gitlab');
  });

  it('resolves SSH URLs to gitlab via isFullGitCloneUrl', () => {
    expect(resolveRegistry('git@git.example.com:team/skills.git')).toBe(
      'gitlab'
    );
  });

  it('respects explicit registry override for shorthand', () => {
    expect(resolveRegistry('lynx/skills', 'gitlab')).toBe('gitlab');
  });

  it('resolves non-GitHub HTTPS URLs to gitlab (bug fix)', () => {
    expect(
      resolveRegistry('https://code.my-gitlab.org/story/skills')
    ).toBe('gitlab');
  });

  it('resolves HTTP URLs to gitlab', () => {
    expect(resolveRegistry('http://git.internal.com/team/repo')).toBe(
      'gitlab'
    );
  });

  it('resolves non-GitHub SSH URLs to gitlab', () => {
    expect(
      resolveRegistry('git@code.my-gitlab.org:story/skills.git')
    ).toBe('gitlab');
  });

  it('resolves file: prefix to file', () => {
    expect(resolveRegistry('file:./local')).toBe('file');
  });

  it('resolves relative path to file', () => {
    expect(resolveRegistry('./relative')).toBe('file');
  });

  it('resolves absolute path to file', () => {
    expect(resolveRegistry('/absolute/path')).toBe('file');
  });
});

import type { RegistryKind } from './types';

/**
 * Detect whether a source string is a full Git clone URL (HTTPS or SSH)
 * rather than an `owner/repo` shorthand or a registry prefix.
 */
export const isFullGitCloneUrl = (source: string): boolean =>
  /^https?:\/\//.test(source) || /^git@[^:]+:.+/.test(source);

/**
 * Determine which source registry to use for a given input string.
 *
 * Resolution order:
 * 1. Local file paths (`file:`, `.`, `/`)
 * 2. Explicit GitHub (`github:` prefix or `github.com/` in URL)
 * 3. Explicit GitLab (`gitlab:` prefix or `gitlab` in URL)
 * 4. Any other full clone URL → GitLab registry (preserves arbitrary URLs)
 * 5. Bare `owner/repo` shorthand → GitHub (default)
 *
 * Non-GitHub/GitLab full clone URLs route through the GitLab registry
 * because it preserves arbitrary HTTPS and SSH origins in the manifest.
 *
 * @example
 * ```ts
 * resolveRegistry('vercel-labs/skills'); // 'github'
 * resolveRegistry('https://self-hosted.example.com/team/repo.git'); // 'gitlab'
 * ```
 */
export const resolveRegistry = (
  source: string,
  registry?: RegistryKind
): RegistryKind => {
  if (
    source.startsWith('file:') ||
    source.startsWith('.') ||
    source.startsWith('/')
  ) {
    return 'file';
  }
  if (source.startsWith('github:') || source.includes('github.com/')) {
    return 'github';
  }
  if (source.startsWith('gitlab:') || source.includes('gitlab')) {
    return 'gitlab';
  }
  if (isFullGitCloneUrl(source)) {
    return registry ?? 'gitlab';
  }
  return registry ?? 'github';
};

